use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub enum Sector {
    Energy, Auto, Agriculture, Finance, Tech, Housing,
    Manufacturing, Healthcare, Retail, Defense,
}

#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub enum SimEvent {
    // Macro
    FiscalBill {
        bill_type: String,      // tax_cut, spending, mandate, regulation
        sector: Option<Sector>,
        amount_gdp_pct: f64,
        distributional_target: Option<String>,
    },
    MonetaryPolicy {
        fed_funds_delta: f64,
    },
    EconomyShock {
        shock_type: String,     // stimulus, austerity, supply_disruption, demand_collapse
        magnitude: f64,
        duration_weeks: u32,
    },

    // Sector
    SectorShock {
        sector: Sector,
        region: Option<String>,
        severity: f64,          // -1.0 to 1.0
    },
    Tariff {
        partner: String,
        product: String,
        rate: f64,
    },

    // Political
    Scandal {
        actor: String,
        severity: f64,
        scandal_type: String,   // financial, personal, policy, foreign
        media_amplification: f64,
    },
    Protest {
        protest_type: String,   // economic, racial, political, environmental
        scale: f64,
        region: String,
        police_response: String,
    },

    // Social
    MediaCampaign {
        campaign_type: String,  // disinformation, true_narrative, advertising
        target_group: String,
        intensity: f64,
        source: String,         // domestic, foreign
    },
    NaturalDisaster {
        disaster_type: String,  // hurricane, wildfire, earthquake, pandemic, flood
        region: String,
        severity: f64,
    },

    // Geopolitical
    Conflict {
        parties: Vec<String>,
        conflict_type: String,  // military, economic, cyber, proxy
        escalation_level: f64,
    },
    Sanction {
        target_country: String,
        sector: Option<Sector>,
        intensity: f64,
    },
    AllianceShift {
        country: String,
        direction: String,      // closer, weaker
        domain: String,         // military, trade, intel
    },
}

#[derive(Debug, Default)]
pub struct SimEventQueue {
    events: Vec<SimEvent>,
}

impl SimEventQueue {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn push(&mut self, event: SimEvent) {
        self.events.push(event);
    }

    pub fn flush(&mut self) -> Vec<SimEvent> {
        std::mem::take(&mut self.events)
    }

    pub fn is_empty(&self) -> bool {
        self.events.is_empty()
    }
}
